        "travel autonomy":                      { section:"reading", ipa:"/ɔːˈtɒn.ə.mi/", stressed:"To", meaning:"sự tự chủ trong di chuyển", type:"phrase", collocation:"provide travel autonomy to", example:"Driverless cars could provide travel autonomy to elderly and disabled people who cannot drive.", connotation:"positive" },
